    if atomic_type is not None: attributes["atomic_type"] = (atomic_type if (
        isinstance(atomic_type, _ods_ir.Attribute) or
        not _ods_ir.AttrBuilder.contains('MosaicGPU_AtomicOpType')) else
          _ods_ir.AttrBuilder.get('MosaicGPU_AtomicOpType')(atomic_type, context=_ods_context))
    if multimem is not None: attributes["multimem"] = (multimem if (
        isinstance(multimem, _ods_ir.Attribute) or
        not _ods_ir.AttrBuilder.contains('BoolAttr')) else
          _ods_ir.AttrBuilder.get('BoolAttr')(multimem, context=_ods_context))
    results = []
    _ods_successors = None
    super().__init__(self.OPERATION_NAME, self._ODS_REGIONS, self._ODS_OPERAND_SEGMENTS, self._ODS_RESULT_SEGMENTS, attributes=attributes, results=results, operands=operands, successors=_ods_successors, regions=regions, loc=loc, ip=ip)

